import{_ as e,o as a,c as t,Q as r}from"./chunks/framework.6d94f49f.js";const _=JSON.parse('{"title":"probe 探针","description":"","frontmatter":{},"headers":[],"relativePath":"DevOps/Kubernetes/基础/pod/probe.md","filePath":"DevOps/Kubernetes/基础/pod/probe.md","lastUpdated":1701275547000}'),o={name:"DevOps/Kubernetes/基础/pod/probe.md"},l=r('<h1 id="probe-探针" tabindex="-1">probe 探针 <a class="header-anchor" href="#probe-探针" aria-label="Permalink to &quot;probe 探针&quot;">​</a></h1><ul><li><a href="./liveProbe">存活探针</a></li><li><a href="./readinessProbe">就绪探针</a></li><li><a href="./startupProbe">启动探针</a></li></ul><h2 id="执行顺序" tabindex="-1">执行顺序 <a class="header-anchor" href="#执行顺序" aria-label="Permalink to &quot;执行顺序&quot;">​</a></h2><p>如果三个探针同时存在，则先执行startupProbe探针，其他两个探针将会被暂时禁用，直到startupProbe一次探测成功，其他2个探针才启动</p><p>如果startupProbe探测失败，kubelet 将杀死容器，并根据restartPolicy重启策略来判断容器是否要进行重启操作。</p><h2 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h2><p>就绪探针与存活探针之间的重要区别：如果容器未通过准备检查，则不会被终止或重新启动。</p><p>存活探针：通过杀死异常的容器，并用新的正常容器替代他们来保持Pod正常工作。</p><p>就绪探针：确保只有准备好处理请求的Pod才可以接收探针请求。</p><h2 id="探测机制" tabindex="-1">探测机制 <a class="header-anchor" href="#探测机制" aria-label="Permalink to &quot;探测机制&quot;">​</a></h2><p>大致分为两类，要么使用系统命令，要么程序提供服务，k8s发请求判断。</p><ul><li>HTTP GET探针</li><li>TCP套接字探针</li><li>Exec探针</li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>三种探测方式配置几乎一样，都是通过httpGet、tcpSocket、exec三种方式进行探测。</p>',14),i=[l];function p(s,n,d,h,c,b){return a(),t("div",null,i)}const P=e(o,[["render",p]]);export{_ as __pageData,P as default};
